import{_ as e,o,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const n=JSON.parse('{"title":"1969年 · 解散合伙基金","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-year/1969年.md","filePath":"05_quotes/by-year/1969年.md"}'),u={name:"05_quotes/by-year/1969年.md"};function q(l,t,c,h,s,p){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="_1969年-·-解散合伙基金" tabindex="-1">1969年 · 解散合伙基金 <a class="header-anchor" href="#_1969年-·-解散合伙基金" aria-label="Permalink to &quot;1969年 · 解散合伙基金&quot;">​</a></h1><blockquote><p>&quot;当市场已经无法找到真正的价值时，最好的做法是退出市场。宁可错过机会，也不要亏损本金。&quot;——巴菲特（39岁）</p></blockquote><p>本页收录1969年巴菲特致合伙人信中的经典语录，这是他解散合伙基金、将资金转入伯克希尔的标志性年份。</p><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;当市场已经无法找到符合我们标准的投资机会时，我选择退出。这不是对市场的判断，而是对价值的判断。&quot;</p></blockquote><blockquote><p>&quot;合伙基金在1969年解散，我把所有资金转入伯克希尔。我的合伙人可以选择继续持有伯克希尔，或者变现离场。大多数人选择了留下。&quot;</p></blockquote><blockquote><p>&quot;在1969年的市场里，到处是投机而不是投资。我找不到值得投资的便宜货。&quot;</p></blockquote><blockquote><p>&quot;我不想继续管理一个在市场中找不到价值的合伙基金。这不符合我对自己的要求。&quot;</p></blockquote><blockquote><p>&quot;把资金转入伯克希尔，意味着我的利益和你们完全一致——只有伯克希尔持续创造价值，我的财富才增长。&quot;</p></blockquote><blockquote><p>&quot;这是我投资生涯中最重要的转折点：从管理他人的钱，到拥有自己的企业。从此以后，我用企业的视角来看待一切投资。&quot;</p></blockquote><hr><h2 id="本年背景" tabindex="-1">本年背景 <a class="header-anchor" href="#本年背景" aria-label="Permalink to &quot;本年背景&quot;">​</a></h2><p>1969年，39岁的巴菲特决定解散运营13年的合伙基金。当时道琼斯指数处于历史高点，市场投机气氛浓厚。巴菲特在信中写道：&quot;我已经找不到符合我标准的价格了。&quot;他将合伙人的资金转换为伯克希尔股票，同时清算了表现不佳的纺织业务，开始了真正意义上的资本配置人生。</p><p>这一决定，后来被证明是他一生中最伟大的决定之一。</p><hr><h2 id="深入阅读" tabindex="-1">深入阅读 <a class="header-anchor" href="#深入阅读" aria-label="Permalink to &quot;深入阅读&quot;">​</a></h2><p><a href="/search.html?q=→ 原文翻译">01_letters/1969年/翻译</a> · <a href="/search.html?q=→ 解封信">01_letters/1969年/解散信</a> · <a href="/search.html?q=→ 1962年合伙信元年">05_quotes/by-year/1962年</a></p>',18)])])}const i=e(u,[["render",q]]);export{n as __pageData,i as default};
